public static List<String> fromAnyArray(Object[] values) throws IllegalArgumentException {
    if (values == null) {
        return null;
    } else {
        ArrayList<String> array = new ArrayList<>(values.length);
        for (var value : values) {
            array.add(anyValueToString(value));
        }
        return array;
    }
}

